+public class Main {
+    private static final String OLD_FNATP = "SizeAndTimeBasedFNATP";
+    private static final String OLD_FNATP_FQN = "ch.qos.logback.core.rolling.SizeAndTimeBasedFNATP";
+    private static final String OLD_ROLLING_POLICY = "TimeBasedRollingPolicy";
+    private static final String OLD_ROLLING_POLICY_FQN = "ch.qos.logback.core.rolling.TimeBasedRollingPolicy";
+    private static final String NEW_POLICY = "SizeAndTimeBasedRollingPolicy";
+    private static final String NEW_POLICY_FQN = "ch.qos.logback.core.rolling.SizeAndTimeBasedRollingPolicy";
+    private static final String SET_FILE_NAMING_AND_TRIGGERING_POLICY = "setTimeBasedFileNamingAndTriggeringPolicy";
+    private static final String SET_TIME_BASED_ROLLING_POLICY = "setTimeBasedRollingPolicy";
+
+    public static void main(String[] args) throws IOException {
+        if (args.length != 1) {
+            throw new IllegalArgumentException("Usage: Main <source-root>");
+        }
+
+        Path root = Paths.get(args[0]);
+        JavaParser parser = new JavaParser(new ParserConfiguration());
+
+        Files.walk(root)
+                .filter(path -> path.toString().endsWith(".java"))
+                .forEach(path -> {
+                    try {
+                        rewriteFile(parser, path);
+                    } catch (IOException e) {
+                        throw new RuntimeException("Failed to rewrite " + path, e);
+                    }
+                });
+    }
+
+    private static void rewriteFile(JavaParser parser, Path file) throws IOException {
+        Optional<CompilationUnit> parsed = parser.parse(file).getResult();
+        if (parsed.isEmpty()) {
+            return;
+        }
+
+        CompilationUnit cu = parsed.get();
+        LexicalPreservingPrinter.setup(cu);
+
+        cu.findAll(MethodDeclaration.class).forEach(Main::rewriteCallable);
+        cu.findAll(ConstructorDeclaration.class).forEach(Main::rewriteCallable);
+
+        rewriteImports(cu);
+        rewriteGlobalTypeNames(cu);
+
+        String rewritten = LexicalPreservingPrinter.print(cu);
+        Files.writeString(file, rewritten, StandardCharsets.UTF_8);
+    }
+
+    private static void rewriteImports(CompilationUnit cu) {
+        cu.getImports().forEach(importDecl -> {
+            String name = importDecl.getNameAsString();
+            if (OLD_FNATP_FQN.equals(name)) {
+                importDecl.setName(NEW_POLICY_FQN);
+            }
+        });
+    }
+
+    private static void rewriteGlobalTypeNames(CompilationUnit cu) {
+        cu.findAll(ClassOrInterfaceType.class).forEach(type -> {
+            if (matchesType(type, OLD_FNATP) || matchesType(type, OLD_FNATP_FQN)) {
+                type.setName(NEW_POLICY);
+            }
+        });
+
+        cu.findAll(ObjectCreationExpr.class).forEach(creation -> {
+            if (matchesType(creation.getType(), OLD_FNATP) || matchesType(creation.getType(), OLD_FNATP_FQN)) {
+                creation.setType(NEW_POLICY);
+            }
+        });
+    }
+
+    private static void rewriteCallable(MethodDeclaration method) {
+        method.getBody().ifPresent(body -> rewriteBlock(body));
+    }
+
+    private static void rewriteCallable(ConstructorDeclaration constructor) {
+        constructor.getBody().ifPresent(body -> rewriteBlock(body));
+    }
+
+    private static void rewriteBlock(com.github.javaparser.ast.stmt.BlockStmt body) {
+        Map<String, String> fnatpToPolicy = new HashMap<>();
+        Set<String> policyVars = new HashSet<>();
+        Set<String> fnatpVars = new HashSet<>();
+        List<ExpressionStmt> statementsToRemove = new ArrayList<>();
+
+        body.findAll(VariableDeclarator.class).forEach(vd -> {
+            if (matchesType(vd.getType(), OLD_ROLLING_POLICY) || matchesType(vd.getType(), OLD_ROLLING_POLICY_FQN)) {
+                policyVars.add(vd.getNameAsString());
+            }
+            if (matchesType(vd.getType(), OLD_FNATP) || matchesType(vd.getType(), OLD_FNATP_FQN)) {
+                fnatpVars.add(vd.getNameAsString());
+            }
+        });
+
+        body.findAll(MethodCallExpr.class).forEach(call -> {
+            if (call.getNameAsString().equals(SET_FILE_NAMING_AND_TRIGGERING_POLICY)) {
+                extractName(call.getScope()).ifPresent(scopeName -> {
+                    if (!call.getArguments().isEmpty()) {
+                        extractName(call.getArgument(0)).ifPresent(argName -> {
+                            fnatpToPolicy.put(argName, scopeName);
+                            policyVars.add(scopeName);
+                            fnatpVars.add(argName);
+                        });
+                    }
+                });
+            }
+        });
+
+        body.findAll(VariableDeclarator.class).forEach(vd -> {
+            if (policyVars.contains(vd.getNameAsString()) &&
+                    (matchesType(vd.getType(), OLD_ROLLING_POLICY) || matchesType(vd.getType(), OLD_ROLLING_POLICY_FQN))) {
+                vd.setType(NEW_POLICY);
+            }
+            if (fnatpVars.contains(vd.getNameAsString()) &&
+                    (matchesType(vd.getType(), OLD_FNATP) || matchesType(vd.getType(), OLD_FNATP_FQN))) {
+                vd.setType(NEW_POLICY);
+            }
+
+            vd.getInitializer().ifPresent(initializer -> {
+                if (initializer.isObjectCreationExpr()) {
+                    ObjectCreationExpr creation = initializer.asObjectCreationExpr();
+                    if (matchesType(creation.getType(), OLD_ROLLING_POLICY) || matchesType(creation.getType(), OLD_ROLLING_POLICY_FQN)
+                            || matchesType(creation.getType(), OLD_FNATP) || matchesType(creation.getType(), OLD_FNATP_FQN)) {
+                        creation.setType(NEW_POLICY);
+                    }
+                }
+            });
+        });
+
+        body.findAll(MethodCallExpr.class).forEach(call -> {
+            String methodName = call.getNameAsString();
+            Optional<String> scopeName = extractName(call.getScope());
+
+            if (methodName.equals(SET_FILE_NAMING_AND_TRIGGERING_POLICY) || methodName.equals(SET_TIME_BASED_ROLLING_POLICY)) {
+                if (call.getParentNode().filter(ExpressionStmt.class::isInstance).isPresent()) {
+                    statementsToRemove.add(call.findAncestor(ExpressionStmt.class).orElseThrow());
+                }
+                return;
+            }
+
+            if (scopeName.isEmpty()) {
+                return;
+            }
+
+            String currentScope = scopeName.get();
+            if (fnatpToPolicy.containsKey(currentScope)) {
+                if (!methodName.equals(SET_TIME_BASED_ROLLING_POLICY)) {
+                    call.setScope(new NameExpr(fnatpToPolicy.get(currentScope)));
+                }
+            }
+        });
+
+        statementsToRemove.forEach(ExpressionStmt::remove);
+    }
+
+    private static Optional<String> extractName(Optional<Expression> scope) {
+        if (scope.isEmpty()) {
+            return Optional.empty();
+        }
+        return extractName(scope.get());
+    }
+
+    private static Optional<String> extractName(Expression expression) {
+        if (expression.isNameExpr()) {
+            return Optional.of(expression.asNameExpr().getNameAsString());
+        }
+        return Optional.empty();
+    }
+
+    private static boolean matchesType(ClassOrInterfaceType type, String expected) {
+        String actual = type.asString();
+        return expected.equals(actual) || expected.equals(type.getNameAsString()) || actual.endsWith('.' + expected);
+    }
+}
