+    private static final String OLD_ROLLING_POLICY_FQN = "ch.qos.logback.core.rolling.TimeBasedRollingPolicy";
+    private static final String NEW_POLICY = "SizeAndTimeBasedRollingPolicy";
+    private static final String NEW_POLICY_FQN = "ch.qos.logback.core.rolling.SizeAndTimeBasedRollingPolicy";
+    private static final String SET_FILE_NAMING_AND_TRIGGERING_POLICY = "setTimeBasedFileNamingAndTriggeringPolicy";
+    private static final String SET_TIME_BASED_ROLLING_POLICY = "setTimeBasedRollingPolicy";
+
+    public static void main(String[] args) throws IOException {
+        if (args.length != 1) {
+            throw new IllegalArgumentException("Usage: Main <source-root>");
+        }
+
+        Path root = Paths.get(args[0]);
+        JavaParser parser = new JavaParser(new ParserConfiguration());
+
+        Files.walk(root)
+                .filter(path -> path.toString().endsWith(".java"))
+                .forEach(path -> {
+                    try {
+                        rewriteFile(parser, path);
+                    } catch (IOException e) {
+                        throw new RuntimeException("Failed to rewrite " + path, e);
+                    }
+                });
+    }
+
+    private static void rewriteFile(JavaParser parser, Path file) throws IOException {
+        Optional<CompilationUnit> parsed = parser.parse(file).getResult();
+        if (parsed.isEmpty()) {
+            return;
+        }
+
+        CompilationUnit cu = parsed.get();
+        LexicalPreservingPrinter.setup(cu);
+
+        cu.findAll(MethodDeclaration.class).forEach(Main::rewriteCallable);
+        cu.findAll(ConstructorDeclaration.class).forEach(Main::rewriteCallable);
+
+        rewriteImports(cu);
+        rewriteGlobalTypeNames(cu);
+
+        String rewritten = LexicalPreservingPrinter.print(cu);
+        Files.writeString(file, rewritten, StandardCharsets.UTF_8);
+    }
+
