+        cu.getImports().forEach(importDecl -> {
+            String name = importDecl.getNameAsString();
+            if (OLD_FNATP_FQN.equals(name)) {
+                importDecl.setName(NEW_POLICY_FQN);
+            }
+        });
+    }
