+        cu.findAll(ClassOrInterfaceType.class).forEach(type -> {
+            if (matchesType(type, OLD_FNATP) || matchesType(type, OLD_FNATP_FQN)) {
+                type.setName(NEW_POLICY);
+            }
+        });
+
+        cu.findAll(ObjectCreationExpr.class).forEach(creation -> {
+            if (matchesType(creation.getType(), OLD_FNATP) || matchesType(creation.getType(), OLD_FNATP_FQN)) {
+                creation.setType(NEW_POLICY);
+            }
+        });
+    }
+
+    private static void rewriteCallable(MethodDeclaration method) {
+        method.getBody().ifPresent(body -> rewriteBlock(body));
+    }
+
